	if (!body.trim()) {
		return { ok: true, value: {} };
	}

	let parsed: unknown;

	try {
		parsed = JSON.parse(body);
	} catch {
		return { ok: false, error: "Request body must be valid JSON when provided." };
	}

	if (!isRecord(parsed)) {
		return { ok: false, error: "Request body must be a JSON object." };
	}

	if (parsed.repositoryUrl === undefined) {
		return { ok: true, value: {} };
	}

	if (typeof parsed.repositoryUrl !== "string" || !parsed.repositoryUrl.trim()) {
		return { ok: false, error: "repositoryUrl must be a non-empty string when provided." };
	}

	const trimmed = parsed.repositoryUrl.trim();
	if (!/^https?:\/\/[^/]+/.test(trimmed)) {
		return { ok: false, error: "repositoryUrl must be a valid URL when provided." };
	}

	return { ok: true, value: { repositoryUrl: trimmed } };
}

function buildTiming(startedAt: number): Timing {
	const finishedAt = Date.now();

	return {
		startedAt,
		finishedAt,
		durationMs: finishedAt - startedAt,
	};
}

function serializeError(error: unknown) {
	if (error instanceof Error) {
		return {
			name: error.name,
			message: error.message,
		};
	}

	return { name: "UnknownError", message: String(error) };
}

function isAllowedRepositoryHost(hostname: string) {
	const lowered = hostname.toLowerCase();
	return lowered === "github.com" || lowered === "api.github.com" || lowered.endsWith(".github.com");
}

